#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>
#include <errno.h>

#define MAX_PATH 4096
#define MAX_FILES 1000
#define MAX_COMMITS 10000
#define MAX_CONTENT 100000

typedef struct {
    char path[MAX_PATH];
    char hash[41];
} FileEntry;

typedef struct {
    char hash[41];
    char parent[41];
    char message[1024];
    time_t timestamp;
    FileEntry files[MAX_FILES];
    int file_count;
} Commit;

char minigit_dir[MAX_PATH];
char objects_dir[MAX_PATH];
char refs_dir[MAX_PATH];
char head_path[MAX_PATH];
char index_path[MAX_PATH];

void compute_hash(const char *content, size_t len, char *out) {
    unsigned char hash[20];
    for (int i = 0; i < 20; i++) {
        hash[i] = 0;
        for (size_t j = 0; j < len; j++) {
            hash[i] ^= (content[j] + i) & 0xFF;
        }
    }
    for (int i = 0; i < 20; i++) {
        sprintf(out + i * 2, "%02x", hash[i]);
    }
    out[40] = '\0';
}

void write_file(const char *path, const char *content) {
    FILE *f = fopen(path, "w");
    if (!f) { perror(path); exit(1); }
    fprintf(f, "%s", content);
    fclose(f);
}

char* read_file(const char *path, size_t *len) {
    FILE *f = fopen(path, "rb");
    if (!f) return NULL;
    fseek(f, 0, SEEK_END);
    *len = ftell(f);
    fseek(f, 0, SEEK_SET);
    char *buf = malloc(*len + 1);
    fread(buf, 1, *len, f);
    buf[*len] = '\0';
    fclose(f);
    return buf;
}

void mkdir_p(const char *dir) {
    char tmp[MAX_PATH];
    snprintf(tmp, sizeof(tmp), "%s", dir);
    for (char *p = tmp + 1; *p; p++) {
        if (*p == '/') {
            *p = '\0';
            mkdir(tmp, 0755);
            *p = '/';
        }
    }
    mkdir(tmp, 0755);
}

void init() {
    snprintf(minigit_dir, sizeof(minigit_dir), ".minigit");
    snprintf(objects_dir, sizeof(objects_dir), "%s/objects", minigit_dir);
    snprintf(refs_dir, sizeof(refs_dir), "%s/refs", minigit_dir);
    snprintf(head_path, sizeof(head_path), "%s/HEAD", minigit_dir);
    snprintf(index_path, sizeof(index_path), "%s/index", minigit_dir);

    mkdir_p(minigit_dir);
    mkdir_p(objects_dir);
    mkdir_p(refs_dir);
    write_file(head_path, "refs/heads/main");
    write_file(index_path, "");
    printf("Initialized empty minigit repository\n");
}

void add(const char *paths[], int count) {
    char index_content[MAX_CONTENT] = "";
    for (int i = 0; i < count; i++) {
        size_t len;
        char *content = read_file(paths[i], &len);
        if (!content) {
            fprintf(stderr, "error: %s: No such file or directory\n", paths[i]);
            exit(1);
        }
        char hash[41];
        compute_hash(content, len, hash);
        char obj_path[MAX_PATH];
        snprintf(obj_path, sizeof(obj_path), "%s/%s", objects_dir, hash);
        write_file(obj_path, content);
        strcat(index_content, paths[i]);
        strcat(index_content, " ");
        strcat(index_content, hash);
        strcat(index_content, "\n");
        free(content);
    }
    write_file(index_path, index_content);
}

char* get_head_ref() {
    static char ref[MAX_PATH];
    FILE *f = fopen(head_path, "r");
    if (!f) return NULL;
    fgets(ref, sizeof(ref), f);
    ref[strcspn(ref, "\n")] = '\0';
    fclose(f);
    return ref;
}

char* get_head_hash() {
    static char hash[41];
    char *ref = get_head_ref();
    if (!ref) return NULL;
    char ref_path[MAX_PATH];
    snprintf(ref_path, sizeof(ref_path), "%s/%s", minigit_dir, ref);
    size_t len;
    char *content = read_file(ref_path, &len);
    if (!content) return NULL;
    strncpy(hash, content, 40);
    hash[40] = '\0';
    free(content);
    return hash;
}

void set_head_hash(const char *hash) {
    char *ref = get_head_ref();
    char ref_path[MAX_PATH];
    snprintf(ref_path, sizeof(ref_path), "%s/%s", minigit_dir, ref);
    write_file(ref_path, hash);
}

void commit(const char *message) {
    char *parent = get_head_hash();
    if (!parent) parent = "";
    size_t index_len;
    char *index_content = read_file(index_path, &index_len);
    if (!index_content) index_content = strdup("");

    char commit_content[MAX_CONTENT];
    snprintf(commit_content, sizeof(commit_content), "parent %s\n%s", parent, index_content);
    char commit_hash[41];
    compute_hash(commit_content, strlen(commit_content), commit_hash);

    char commit_path[MAX_PATH];
    snprintf(commit_path, sizeof(commit_path), "%s/%s", objects_dir, commit_hash);
    write_file(commit_path, commit_content);

    set_head_hash(commit_hash);
    printf("Committed %s\n", commit_hash);
    free(index_content);
}

void load_commit(const char *hash, Commit *commit) {
    strcpy(commit->hash, hash);
    char path[MAX_PATH];
    snprintf(path, sizeof(path), "%s/%s", objects_dir, hash);
    size_t len;
    char *content = read_file(path, &len);
    if (!content) {
        fprintf(stderr, "error: commit %s not found\n", hash);
        exit(1);
    }
    char *line = strtok(content, "\n");
    strcpy(commit->parent, "");
    commit->file_count = 0;
    while (line) {
        if (strncmp(line, "parent ", 7) == 0) {
            strcpy(commit->parent, line + 7);
        } else {
            char path[MAX_PATH], hash[41];
            if (sscanf(line, "%s %s", path, hash) == 2) {
                strcpy(commit->files[commit->file_count].path, path);
                strcpy(commit->files[commit->file_count].hash, hash);
                commit->file_count++;
            }
        }
        line = strtok(NULL, "\n");
    }
    free(content);
}

void checkout(const char *target) {
    char commit_hash[41];
    if (strcmp(target, "HEAD") == 0) {
        char *h = get_head_hash();
        if (!h) {
            fprintf(stderr, "error: HEAD not found\n");
            exit(1);
        }
        strcpy(commit_hash, h);
    } else if (strncmp(target, "HEAD~", 5) == 0) {
        int n = atoi(target + 5);
        char *h = get_head_hash();
        if (!h) {
            fprintf(stderr, "error: HEAD not found\n");
            exit(1);
        }
        strcpy(commit_hash, h);
        for (int i = 0; i < n; i++) {
            Commit c;
            load_commit(commit_hash, &c);
            if (strlen(c.parent) == 0) {
                fprintf(stderr, "error: %s not found\n", target);
                exit(1);
            }
            strcpy(commit_hash, c.parent);
        }
    } else {
        fprintf(stderr, "error: unsupported target '%s'\n", target);
        exit(1);
    }

    Commit c;
    load_commit(commit_hash, &c);
    for (int i = 0; i < c.file_count; i++) {
        char obj_path[MAX_PATH];
        snprintf(obj_path, sizeof(obj_path), "%s/%s", objects_dir, c.files[i].hash);
        size_t len;
        char *content = read_file(obj_path, &len);
        if (!content) {
            fprintf(stderr, "error: object %s not found\n", c.files[i].hash);
            exit(1);
        }
        write_file(c.files[i].path, content);
        free(content);
    }
    set_head_hash(commit_hash);
}

void reset(const char *mode, const char *target) {
    if (strcmp(mode, "--hard") != 0) {
        fprintf(stderr, "error: unsupported reset mode '%s'\n", mode);
        exit(1);
    }
    char commit_hash[41];
    if (strncmp(target, "HEAD~", 5) == 0) {
        int n = atoi(target + 5);
        char *h = get_head_hash();
        if (!h) {
            fprintf(stderr, "error: HEAD not found\n");
            exit(1);
        }
        strcpy(commit_hash, h);
        for (int i = 0; i < n; i++) {
            Commit c;
            load_commit(commit_hash, &c);
            if (strlen(c.parent) == 0) {
                fprintf(stderr, "error: %s not found\n", target);
                exit(1);
            }
            strcpy(commit_hash, c.parent);
        }
    } else {
        fprintf(stderr, "error: unsupported target '%s'\n", target);
        exit(1);
    }

    Commit c;
    load_commit(commit_hash, &c);
    for (int i = 0; i < c.file_count; i++) {
        char obj_path[MAX_PATH];
        snprintf(obj_path, sizeof(obj_path), "%s/%s", objects_dir, c.files[i].hash);
        size_t len;
        char *content = read_file(obj_path, &len);
        if (!content) {
            fprintf(stderr, "error: object %s not found\n", c.files[i].hash);
            exit(1);
        }
        write_file(c.files[i].path, content);
        free(content);
    }
    set_head_hash(commit_hash);
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        fprintf(stderr, "usage: minigit <command> [<args>]\n");
        return 1;
    }
    if (strcmp(argv[1], "init") == 0) {
        init();
    } else if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) {
            fprintf(stderr, "usage: minigit add <file>...\n");
            return 1;
        }
        add((const char**)(argv + 2), argc - 2);
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 4 || strcmp(argv[2], "-m") != 0) {
            fprintf(stderr, "usage: minigit commit -m <message>\n");
            return 1;
        }
        commit(argv[3]);
    } else if (strcmp(argv[1], "checkout") == 0) {
        if (argc < 3) {
            fprintf(stderr, "usage: minigit checkout <target>\n");
            return 1;
        }
        checkout(argv[2]);
    } else if (strcmp(argv[1], "reset") == 0) {
        if (argc < 4) {
            fprintf(stderr, "usage: minigit reset <mode> <target>\n");
            return 1;
        }
        reset(argv[2], argv[3]);
    } else {
        fprintf(stderr, "error: unknown command '%s'\n", argv[1]);
        return 1;
    }
    return 0;
}
